// Load js-dos v8 CSS
var css = document.createElement("link");
css.rel = "stylesheet";
css.href = "https://v8.js-dos.com/latest/js-dos.css";
document.head.appendChild(css);

// Load js-dos v8 script
var script = document.createElement("script");
script.src = "https://v8.js-dos.com/latest/js-dos.js";
script.onload = function() {
  console.log("[doom] js-dos loaded, initializing...");

  // Create hidden container for js-dos
  var container = document.getElementById("jsdos-doom");
  if (container) container.remove();
  container = document.createElement("div");
  container.id = "jsdos-doom";
  container.style.cssText = "position:fixed;left:-9999px;top:0;width:640px;height:400px;overflow:hidden;";
  document.body.appendChild(container);

  // Kill hud-draw on center monitor so it doesn't overwrite
  document.querySelectorAll("a-entity").forEach(function(e) {
    var comp = e.components && e.components["hud-draw"];
    if (!comp) return;
    if (!comp.canvas || comp.canvas.id !== "hud-canvas-center") return;
    comp.tick = function() {};
    console.log("[doom] killed hud-draw tick on center monitor");
  });

  // Initialize DOOM
  var props = Dos(container, {
    url: "https://v8.js-dos.com/bundles/doom.jsdos",
    autoStart: true,
  });

  // Poll for the js-dos canvas and pipe to center monitor
  var pipeInterval = setInterval(function() {
    var jsdosCanvas = container.querySelector("canvas");
    if (!jsdosCanvas) return;
    if (jsdosCanvas.width < 10) return;

    console.log("[doom] found js-dos canvas:", jsdosCanvas.width, "x", jsdosCanvas.height);
    clearInterval(pipeInterval);

    var target = document.getElementById("hud-canvas-center");
    target.width = 512;
    target.height = 512;
    var tctx = target.getContext("2d");

    // Pipe js-dos frames to the VR monitor canvas
    function pipe() {
      tctx.fillStyle = "#000";
      tctx.fillRect(0, 0, 512, 512);
      // Scale DOOM output to fit the 512x512 canvas (maintain aspect ratio)
      var sw = jsdosCanvas.width, sh = jsdosCanvas.height;
      var scale = Math.min(512 / sw, 512 / sh);
      var dw = sw * scale, dh = sh * scale;
      var dx = (512 - dw) / 2, dy = (512 - dh) / 2;
      tctx.drawImage(jsdosCanvas, 0, 0, sw, sh, dx, dy, dw, dh);
      // Header bar
      tctx.fillStyle = "#001008";
      tctx.fillRect(0, 0, 512, 20);
      tctx.fillStyle = "#00aa44";
      tctx.font = "bold 10px monospace";
      tctx.fillText("MAIN // DOOM // js-dos", 8, 14);
      requestAnimationFrame(pipe);
    }
    pipe();
  }, 500);
};
document.head.appendChild(script);
console.log("[doom] loading js-dos v8...");
